import { useState, useEffect } from "react";
import { supabase } from "../supabaseClient";
import "./PostCard.css";

const PostCard = ({ post }) => {
  const [user, setUser] = useState(null);
  const [liked, setLiked] = useState(false);
  const [likeCount, setLikeCount] = useState(0);
  const [following, setFollowing] = useState(false);
  const [comment, setComment] = useState("");
  const [comments, setComments] = useState([]);
  const [showComments, setShowComments] = useState(false);

  useEffect(() => {
    initialize();
    // eslint-disable-next-line
  }, []);

  // ================= INITIALIZE =================
  const initialize = async () => {
    const { data } = await supabase.auth.getUser();
    const currentUser = data?.user;

    setUser(currentUser);

    await fetchLikes();
    await checkLike(currentUser);
    await checkFollow(currentUser);
  };

  // ================= GET USER =================
  const getUser = async () => {
    const { data } = await supabase.auth.getUser();
    setUser(data?.user);
  };

  // ================= LIKE =================

  const fetchLikes = async () => {
    const { data } = await supabase
      .from("likes")
      .select("*")
      .eq("post_id", post.id);

    setLikeCount(data ? data.length : 0);
  };

  const checkLike = async (currentUser) => {
    if (!currentUser) return;

    const { data } = await supabase
      .from("likes")
      .select("*")
      .eq("user_id", currentUser.id)
      .eq("post_id", post.id);

    if (data.length > 0) setLiked(true);
  };

  const handleLike = async () => {
    if (!user) return;

    if (liked) {
      await supabase
        .from("likes")
        .delete()
        .eq("user_id", user.id)
        .eq("post_id", post.id);

      setLiked(false);
      setLikeCount((prev) => prev - 1);
    } else {
      const { error } = await supabase.from("likes").insert([
        { user_id: user.id, post_id: post.id },
      ]);

      if (!error) {
        setLiked(true);
        setLikeCount((prev) => prev + 1);
      }
    }
  };

  // ================= FOLLOW =================

  const checkFollow = async (currentUser) => {
    if (!currentUser) return;

    const { data } = await supabase
      .from("follows")
      .select("*")
      .eq("follower_id", currentUser.id)
      .eq("following_id", post.user_id);

    if (data.length > 0) setFollowing(true);
  };

  const handleFollow = async () => {
    if (!user) return;

    if (following) {
      await supabase
        .from("follows")
        .delete()
        .eq("follower_id", user.id)
        .eq("following_id", post.user_id);

      setFollowing(false);
    } else {
      await supabase.from("follows").insert([
        {
          follower_id: user.id,
          following_id: post.user_id,
        },
      ]);

      setFollowing(true);
    }
  };

// ================= DELETE POST =================
  const handleDelete= async () => {
    if (!user) return;

    const confirmDelete = window.confirm("Delete this post?");
    if (!confirmDelete) return;

    try {
      // delete likes
      await supabase.from("likes").delete().eq("post_id", post.id);

      // delete comments
      await supabase.from("comments").delete().eq("post_id", post.id);

      // delete post
      const { error } = await supabase
        .from("posts")
        .delete()
        .eq("id", post.id);

      if (error) {
        console.log(error);
        alert("Delete failed");
      } else {
        alert("Post deleted");

        // 🔥 refresh feed
        window.location.reload();
      }
    } catch (err) {
      console.log(err);
    }
  };

  // ================= COMMENTS =================

  const fetchComments = async () => {
    const { data, error } = await supabase
      .from("comments")
      .select(`
        *,
        profiles (name)
      `)
      .eq("post_id", post.id)
      .order("created_at", { ascending: false });

    if (error) {
      console.log(error);
    } else {
      setComments(data || []);
    }
  };

  const handleComment = async () => {
    if (!user || comment.trim() === "") return;

    await supabase.from("comments").insert([
      {
        user_id: user.id,
        post_id: post.id,
        content: comment,
      },
    ]);

    setComment("");
    fetchComments();
  };

  const toggleComments = async () => {
    if (!showComments) {
      await fetchComments();
    }
    setShowComments((prev) => !prev);
  };

  // ================= IMAGE LOGIC =================

  let images = [];

  if (post.image_urls && post.image_urls.length > 0) {
    images = post.image_urls;
  } else if (post.image_url) {
    images = [post.image_url];
  }

  // ================= UI =================

  return (
    <div className="post-card">

        {/* HEADER */}
        <div className="post-header">
    <div className="user-info">
      <div className="avatar">👤</div>
      <span className="username">User</span>
    </div>

    {/* FOLLOW BUTTON */}
    {user && user.id !== post.user_id && (
      <button className="follow-btn" onClick={handleFollow}>
        {following ? "Following" : "Follow"}
      </button>
    )}

    {/* DELETE BUTTON (ONLY OWNER) */}
    {user && user.id === post.user_id && (
      <button className="delete-btn" onClick={handleDelete}>
        Delete
      </button>
    )}
  </div>

      {/* CONTENT */}
      <div className="post-content">
        <p>{post.content}</p>
      </div>

      {/* IMAGES */}
      {images.length > 0 && (
        <div className="post-image-container">
          {images.map((img, index) => (
            <img key={index} src={img} alt="post" />
          ))}
        </div>
      )}

      {/* ACTIONS */}
      <div className="post-actions">
        <button className="like-btn" onClick={handleLike}>
          {liked ? "❤️" : "🤍"} {likeCount}
        </button>
      </div>

      {/* SHOW COMMENTS BUTTON */}
      <p className="view-comments-btn" onClick={toggleComments}>
        {showComments ? "Hide comments" : "Show comments"}
      </p>

      {/* COMMENTS */}
      {showComments && (
        <>
          <div className="comments-container">
            {comments.map((c) => (
              <div key={c.id} className="comment-item">
                <span className="comment-user">
                  {c.profiles?.name || "User"}
                </span>
                : {c.content}
              </div>
            ))}
          </div>

          <div className="comment-box">
            <input
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              placeholder="Write a comment..."
            />
            <button onClick={handleComment}>Post</button>
          </div>
        </>
      )}

    </div>
  );
};

export default PostCard;
